function escapeHtml(text) {

  if (text === undefined || text === null) return "";

  return String(text)
    .replace(/&/g, "&amp;")
    .replace(/</g, "&lt;")
    .replace(/>/g, "&gt;")
    .replace(/\n/g, "<br>");

}



function renderList(items){

  if(!Array.isArray(items)) return "";

  return `
  <ul>
  ${items.map(item => `
    <li>${escapeHtml(item)}</li>
  `).join("")}
  </ul>
  `;

}



